import heapq
from collections import Counter


class Solution:
    def findLeastNumOfUniqueInts(self, arr, k):
        cnt = Counter(arr)
        heap = [(c, v) for v, c in cnt.items()]
        heapq.heapify(heap)
        remaining = k
        while remaining > 0 and heap:
            c, v = heapq.heappop(heap)
            c -= 1
            remaining -= 1
            if c > 0:
                heapq.heappush(heap, (c, v))
        return len(heap)

