from collections import Counter


class Solution:
    def findLeastNumOfUniqueInts(self, arr, k):
        cnt = Counter(arr)
        freqs = sorted(cnt.values())
        remaining = len(freqs)
        for f in freqs:
            if k >= f:
                k -= f
                remaining -= 1
            else:
                break
        return remaining

